<%_
// ====== 季节判定 ======
const _日期str = getvar('stat_data.世界.日期') || '';
const _dateMatch = _日期str.match(/(\d{4})\/(\d{1,2})\/(\d{1,2})/);
const _年 = _dateMatch ? parseInt(_dateMatch[1]) : 1931;
const _月 = _dateMatch ? parseInt(_dateMatch[2]) : 5;
const _日 = _dateMatch ? parseInt(_dateMatch[3]) : 1;
const _季 = _月 >= 3 && _月 <= 5 ? '春' : _月 >= 6 && _月 <= 8 ? '夏'
          : _月 >= 9 && _月 <= 11 ? '秋' : '冬';
const _季效 = {
  '春': '播种期,青黄不接粮价偏高',
  '夏': '汛期,长江水路风险高,瘟疫减员',
  '秋': '收获期,粮价回落,商业旺季',
  '冬': '休耕消耗,北方水路冰封,补给消耗增'
};
// ====== 星期计算 ======
const _weekNames = ['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];
const _weekDay = (() => {
  if (!_dateMatch) return '星期一';
  const _d = new Date(_年, _月 - 1, _日);
  return _weekNames[_d.getDay()];
})();
// ====== 货币制度检测 ======
const _货币制度 = getvar('stat_data.经济行情.货币制度') || '银本位';
const _币名 = _货币制度 === '银本位' ? '银元' : _货币制度 === '法币' ? '法币' : _货币制度 === '金圆券' ? '金圆券' : _货币制度;
const _是银本位 = _货币制度 === '银本位';
_%>
世界:
  {{format_message_variable::stat_data.世界}}
  季节: <%- _季 %>（<%- _季效[_季] %>）
  星期: <%- _weekDay %>
当前位置:
  {{format_message_variable::stat_data.当前位置}}
<%_// ====== 主角（有生日则自动计算年龄并写回变量） ======
const _主角 = getvar('stat_data.主角') || {};
const _主角生日 = _主角.生日 || '';
const _bdMatch = _主角生日.match(/(\d{4})\/(\d{1,2})\/(\d{1,2})/);
if (_bdMatch) {
  const _出生年 = parseInt(_bdMatch[1]);
  const _出生月 = parseInt(_bdMatch[2]);
  const _出生日 = parseInt(_bdMatch[3]);
  let _实际年龄 = _年 - _出生年;
  if (_月 < _出生月 || (_月 === _出生月 && _日 < _出生日)) _实际年龄--;
  setvar('stat_data.主角.年龄', _实际年龄 + '岁');
}
print('主角:\n');
for (const [_mk, _mv] of Object.entries(_主角)) {
  if (_mk.charCodeAt(0) === 36) continue; // skip $-prefixed
  if (typeof _mv === 'object' && _mv !== null) {
    print('  ' + _mk + ':\n');
    for (const [_sk, _sv] of Object.entries(_mv)) {
      if (_sk.charCodeAt(0) === 36) continue;
      if (typeof _sv === 'object' && _sv !== null && !Array.isArray(_sv)) {
        print('    ' + _sk + ':\n');
        for (const [_tk, _tv] of Object.entries(_sv)) {
          if (_tk.charCodeAt(0) !== 36) print('      ' + _tk + ': ' + _tv + '\n');
        }
      } else {
        print('    ' + _sk + ': ' + _sv + '\n');
      }
    }
  } else {
    print('  ' + _mk + ': ' + _mv + '\n');
  }
}
