<%_
// ====== 人物关系（按需注入 + NPC记忆） ======
const _人物 = getvar('stat_data.人物关系');
if (_人物 && Object.keys(_人物).length > 0) {
  const _提到的人 = Object.keys(_人物).filter(name => {
    const _别名 = Array.isArray(_人物[name]?.别名) ? _人物[name].别名 : [];
    return matchChatMessages([name, ..._别名], { start: -4 });
  });
  // 永远输出紧凑名单，让AI知道全部已登记人物（防重复创建）
  const _名单 = Object.entries(_人物).map(([_n, _i]) => {
    const _简 = _n + '(' + (_i.身份 || '?') + '/' + (_i.态度 || '?') + (_i.别名 && _i.别名.length > 0 ? '/曾用:' + _i.别名.join(',') : '') + ')';
    return _简;
  });
  print('已登记人物(' + _名单.length + '人): ' + _名单.join(', ') + '\n');
  if (_提到的人.length > 0) {
    print('人物关系:\n');
    for (const _name of _提到的人) {
      const _info = _人物[_name];
      print('  ' + _name + ':\n');
      // 有生日时自动计算年龄并写回变量
      const _npcBd = (_info['生日'] || '').match(/(\d{4})\/(\d{1,2})\/(\d{1,2})/);
      if (_npcBd) {
        let _npcAge = _年 - parseInt(_npcBd[1]);
        if (_月 < parseInt(_npcBd[2]) || (_月 === parseInt(_npcBd[2]) && _日 < parseInt(_npcBd[3]))) _npcAge--;
        setvar('stat_data.人物关系.' + _name + '.年龄', _npcAge + '岁');
      }
      for (const [_k, _v] of Object.entries(_info)) {
        if (_k === '记忆' || _k.charCodeAt(0) === 36) continue;
        print('    ' + _k + ': ' + _v + '\n');
      }
      // NPC记忆注入：取重要度最高的前3条
      const _npcMem = _info['记忆'];
      if (_npcMem && typeof _npcMem === 'object' && Object.keys(_npcMem).length > 0) {
        const _memArr = Object.entries(_npcMem)
          .map(([_t, _m]) => ({ t: _t, c: _m?.内容 || '', d: _m?.日期 || '', i: Number(_m?.重要度) || 3 }))
          .sort((a, b) => b.i - a.i)
          .slice(0, 3);
        print('    交往记录:\n');
        for (const _m of _memArr) {
          print('      [' + _m.d + '] ' + _m.t + ': ' + _m.c + '\n');
        }
      }
    }
  }
}
