// ====== 历史大事：条件全满时自动将状态写回"已结束" ======
const _历史大事 = getvar('stat_data.历史大事') || {};
for (const _evName of Object.keys(_历史大事)) {
  const _ev = _历史大事[_evName];
  if (!_ev || _ev.状态 === '已结束') continue;
  const _conds = _ev.条件;
  if (!_conds || typeof _conds !== 'object') continue;
  const _ck = Object.keys(_conds);
  if (_ck.length > 0 && _ck.every(_k => {
    const _p = Number(_conds[_k]?.进度) || 0;
    const _m = Number(_conds[_k]?.上限) || 5;
    return _p >= _m;
  })) {
    setvar('stat_data.历史大事.' + _evName + '.状态', '已结束');
  }
}
