<%_
// ====== 记忆智能注入引擎 ======
const _全记忆 = getvar('stat_data.记忆') || {};
const _记忆条目 = Object.entries(_全记忆);
const _总数 = _记忆条目.length;
if (_总数 > 0) {
  const _选中 = new Map(); // key → {标题,条目,分数}
  const _当前城mem = getvar('stat_data.当前位置.所在城镇') || '';
  // 1. 永驻记忆：重要度>=4
  for (const [_k, _v] of _记忆条目) {
    if (_v && (Number(_v.重要度) || 3) >= 4) {
      _选中.set(_k, { 分: 100 + (Number(_v.重要度) || 3) });
    }
  }
  // 2. 城市关联：当前所在城市
  if (_当前城mem) {
    for (const [_k, _v] of _记忆条目) {
      if (_选中.has(_k)) continue;
      const _城 = Array.isArray(_v?.关联城市) ? _v.关联城市 : [];
      if (_城.indexOf(_当前城mem) >= 0) _选中.set(_k, { 分: 60 });
    }
  }
  // 3. 人物关联：对话中提到的NPC
  const _全NPC = Object.keys(getvar('stat_data.人物关系') || {});
  const _提到NPC = _全NPC.filter(_n => {
    const _别名n = Array.isArray(_人物[_n]?.别名) ? _人物[_n].别名 : [];
    return matchChatMessages([_n, ..._别名n], { start: -3 });
  });
  for (const [_k, _v] of _记忆条目) {
    if (_选中.has(_k)) continue;
    const _人 = Array.isArray(_v?.关联人物) ? _v.关联人物 : [];
    if (_提到NPC.some(_n => _人.indexOf(_n) >= 0)) _选中.set(_k, { 分: 50 });
  }
  // 4. 标签匹配：对话关键词
  const _话题词 = [];
  for (const [_k, _v] of _记忆条目) {
    if (_选中.has(_k)) continue;
    const _tags = Array.isArray(_v?.标签) ? _v.标签 : [];
    if (_tags.length > 0 && matchChatMessages(_tags, { start: -3 })) {
      _选中.set(_k, { 分: 40 });
    }
  }
  // 5. 时间近邻：最近3条
  const _按时间 = [..._记忆条目].sort((a, b) => {
    const _da = (a[1]?.日期 || '').replace(/\//g, '');
    const _db = (b[1]?.日期 || '').replace(/\//g, '');
    return _db > _da ? 1 : _db < _da ? -1 : 0;
  });
  for (let _i = 0; _i < Math.min(3, _按时间.length); _i++) {
    const _rk = _按时间[_i][0];
    if (!_选中.has(_rk)) _选中.set(_rk, { 分: 30 - _i });
  }
  // 排序并截断至10条
  const _排序 = [..._选中.entries()].sort((a, b) => {
    const _sa = a[1].分 + (Number(_全记忆[a[0]]?.重要度) || 3);
    const _sb = b[1].分 + (Number(_全记忆[b[0]]?.重要度) || 3);
    return _sb - _sa;
  }).slice(0, 10);
  const _星 = v => '★'.repeat(Math.min(5, Number(v) || 3));
  print('相关记忆(' + _排序.length + '/' + _总数 + '条):\n');
  for (const [_k] of _排序) {
    const _m = _全记忆[_k];
    if (!_m) continue;
    print('  [' + (_m.日期 || '?') + '] ' + _k + ': ' + (_m.内容 || '') + ' (' + _星(_m.重要度) + ')\n');
  }
  if (_总数 > _排序.length) {
    print('  [其余' + (_总数 - _排序.length) + '条记忆已存档，可通过关键词调取]\n');
  }
}
