    const _有效 = Object.entries(_d).filter(([k,v]) => k.charCodeAt(0) !== 36 && v !== '' && v !== '无' && !(typeof v === 'object' && Object.keys(v).length === 0) && !(Array.isArray(v) && v.length === 0));
    if (_有效.length === 0) continue;
