// ====== 财政面板自动计算（控制城市时激活） ======
// 民国财税参考：商税按商业活力×繁荣度、田赋按农业比重、厘金按贸易流量
// 军费约7-10银元/月/兵；县级月收入3000-8000银元，省会20000-50000银元
const _财政 = getvar('stat_data.财政面板');
if (_财政 && _财政.管辖城市) {
  const _管辖城 = _财政.管辖城市;
  const _管城数 = _地图 ? _地图[_管辖城] : null;
  if (_管城数 && typeof _管城数 === 'object') {
    const _fm经 = _管城数.经济 || {};
    const _fm工 = _管城数.工业 || {};
    const _fm安 = _管城数.治安 || {};
    const _fm人 = _管城数.人口 || {};
    const _繁荣 = Number(_fm经.繁荣度) || 50;
    const _商活 = Number(_fm经.商业活力) || 30;
    const _工业化 = Number(_fm工.工业化) || 10;
    const _通达 = Number(_fm经.通达度) || 50;
    const _港口 = Number((_fm工.基础设施 || {}).港口等级) || 0;
    // 收入计算（单位：银元/月）
    // 商税：商业活力和繁荣度越高，商税越多
    const _商税 = Math.round(_商活 * _繁荣 / 100 * 3000);
    // 田赋：农业占比越大（工业化低），田赋越多
    const _田赋 = Math.round((100 - _工业化) / 100 * _繁荣 / 100 * 4000);
    // 厘金：贸易流量（通达度×商业活力）
    const _fm厘金 = Math.round(_通达 / 100 * _商活 / 100 * 3000);
    // 盐税：和人口/繁荣度挂钩
    const _fm盐税 = Math.round(_繁荣 / 100 * 2000);
    // 鸦片税：如果城市有鸦片产业或地下活动包含鸦片
    const _有鸦片 = Object.keys(_管城数.特产 || {}).some(k => k.includes('鸦片')) ||
                   String((_fm安.地下活动) || '').includes('鸦片');
    const _fm鸦片税 = _有鸦片 ? Math.round(_繁荣 / 100 * 3000) : 0;
    // 关税分润：有港口才有
    const _fm关税 = _港口 > 0 ? Math.round(_港口 * _商活 / 100 * 2000) : 0;
    // 写入收入
    setvar('stat_data.财政面板.月度预算.收入.商税', _商税);
    setvar('stat_data.财政面板.月度预算.收入.田赋', _田赋);
    setvar('stat_data.财政面板.月度预算.收入.厘金', _fm厘金);
    setvar('stat_data.财政面板.月度预算.收入.盐税', _fm盐税);
    setvar('stat_data.财政面板.月度预算.收入.鸦片税', _fm鸦片税);
    setvar('stat_data.财政面板.月度预算.收入.关税分润', _fm关税);
    // 总收支
    const _fm总收入 = _商税 + _田赋 + _fm厘金 + _fm盐税 + _fm鸦片税 + _fm关税;
    const _fm支出 = _财政.月度预算?.支出 || {};
    const _fm总支出 = (Number(_fm支出.军费) || 0) + (Number(_fm支出.行政) || 0) +
                    (Number(_fm支出.建设投入) || 0) + (Number(_fm支出.赈灾) || 0) +
                    (Number(_fm支出.靠山孝敬) || 0);
    const _fm月结余 = _fm总收入 - _fm总支出;
    setvar('stat_data.财政面板.月结余', _fm月结余);
    // 财政评级
    const _fm储备 = Number(_财政.财政储备) || 0;
    let _fm评级 = '充裕';
    if (_fm总支出 > 0) {
      const _可撑月 = _fm储备 / _fm总支出;
      _fm评级 = _可撑月 >= 6 ? '充裕' : _可撑月 >= 3 ? '尚可' : _可撑月 >= 1 ? '紧张' : _fm储备 > 0 ? '告急' : '枯竭';
    }
    setvar('stat_data.财政面板.财政评级', _fm评级);
    // 月结：每月1日将结余加到财政储备（用内联计算避免依赖后续变量）
    const _fm月结标 = _年 * 100 + _月;
    const _fm上次结 = Number(getvar('stat_data._财政上次月结')) || 0;
    if (_日 === 1 && _fm月结标 !== _fm上次结) {
      setvar('stat_data.财政面板.财政储备', _fm储备 + _fm月结余);
      setvar('stat_data._财政上次月结', _fm月结标);
    }
  }
}
